parameters.jsCode:
const row = $('Get row(s)').item.json;
const llm = $('Basic LLM Chain (texto)').item.json;

const rawOriginal =
  llm.text ||
  llm.output ||
  llm.response ||
  llm.content ||
  JSON.stringify(llm);

let raw = String(rawOriginal)
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);

  if (!jsonMatch) {
    throw new Error(
      "No se encontró JSON válido en la respuesta del LLM: " +
      raw.slice(0, 700)
    );
  }

  try {
    parsed = JSON.parse(jsonMatch[0]);
  } catch (err) {
    throw new Error(
      "El JSON del LLM no se pudo parsear: " +
      jsonMatch[0].slice(0, 700)
    );
  }
}

const clean = (v) => v == null ? "" : String(v).trim();

const normalizeIdArray = (value) => {
  if (Array.isArray(value)) {
    return value.map(Number).filter(Boolean);
  }

  if (typeof value === "number") {
    return [Number(value)].filter(Boolean);
  }

  if (typeof value === "string") {
    const trimmed = value.trim();

    if (!trimmed || trimmed.startsWith("#")) {
      return [];
    }

    try {
      const parsedValue = JSON.parse(trimmed);
      if (Array.isArray(parsedValue)) {
        return parsedValue.map(Number).filter(Boolean);
      }
    } catch (e) {}

    return trimmed
      .split(",")
      .map(v => Number(v.trim()))
      .filter(Boolean);
  }

  return [];
};

const titleWordpress = clean(parsed.title_wordpress || row.title_wordpress || row.title_current);
const contentWordpress = clean(parsed.content_wordpress || row.content_wordpress || row.content_current);

// String visual. Si quieres permitir tags nuevos manuales desde app,
// deben llegar aquí por row.tags_wordpress. El LLM queda como último fallback.
const tagsWordpress = clean(
  row.tags_wordpress ||
  parsed.tags_wordpress ||
  ""
);

const titleLinkedin = clean(parsed.title_linkedin || row.title_linkedin);
const contentLinkedin = clean(parsed.content_linkedin || row.content_linkedin);
const tagsLinkedin = clean(parsed.tags_linkedin || row.tags_linkedin);

const titleX = clean(parsed.title_x || row.title_x);
const contentX = clean(parsed.content_x || row.content_x);
const tagsX = clean(parsed.tags_x || row.tags_x);

const titleFacebook = clean(parsed.title_facebook || row.title_facebook);
const contentFacebook = clean(parsed.content_facebook || row.content_facebook);
const tagsFacebook = clean(parsed.tags_facebook || row.tags_facebook);

const titleInstagram = clean(parsed.title_instagram || row.title_instagram);
const contentInstagram = clean(parsed.content_instagram || row.content_instagram);
const tagsInstagram = clean(parsed.tags_instagram || row.tags_instagram);

const category = clean(parsed.category || row.category || row.custom_category);
const keyword = clean(parsed.keyword || row.keyword_current);
const imagePrompt = clean(parsed.image_prompt || row.image_prompt_current);

// Array real para WordPress.
// Prioriza lo que venga ya guardado en la fila/app, no lo que invente el LLM.
const wpTagIds =
  normalizeIdArray(row.tags_current).length
    ? normalizeIdArray(row.tags_current)
    : normalizeIdArray(row.tags).length
      ? normalizeIdArray(row.tags)
      : normalizeIdArray(row.tagIds).length
        ? normalizeIdArray(row.tagIds)
        : normalizeIdArray(row.tags_current_ids);

const currentVersionsRaw = row.text_versions || "[]";

let currentVersions = [];

try {
  currentVersions =
    typeof currentVersionsRaw === "string"
      ? JSON.parse(currentVersionsRaw || "[]")
      : Array.isArray(currentVersionsRaw)
        ? currentVersionsRaw
        : [];
} catch (e) {
  currentVersions = [];
}

currentVersions.push({
  version: currentVersions.length + 1,
  source: "regenerated_multichannel_text",
  accepted: true,
  created_at: new Date().toISOString(),

  title: titleWordpress,
  content: contentWordpress,
  tags: tagsWordpress,

  title_wordpress: titleWordpress,
  content_wordpress: contentWordpress,
  tags_wordpress: tagsWordpress,

  title_linkedin: titleLinkedin,
  content_linkedin: contentLinkedin,
  tags_linkedin: tagsLinkedin,

  title_x: titleX,
  content_x: contentX,
  tags_x: tagsX,

  title_facebook: titleFacebook,
  content_facebook: contentFacebook,
  tags_facebook: tagsFacebook,

  title_instagram: titleInstagram,
  content_instagram: contentInstagram,
  tags_instagram: tagsInstagram,

  category,
  keyword,
  image_prompt: imagePrompt,
});

return {
  json: {
    id: row.id,
    session_id: row.session_id,

    title_current: titleWordpress,
    content_current: contentWordpress,

    // WP: array de IDs
    tags_current: wpTagIds,
    tags: wpTagIds,
    tagIds: wpTagIds,
    tags_current_ids: wpTagIds,

    // App / visual
    title_wordpress: titleWordpress,
    content_wordpress: contentWordpress,
    tags_wordpress: tagsWordpress,

    title_linkedin: titleLinkedin,
    content_linkedin: contentLinkedin,
    tags_linkedin: tagsLinkedin,

    title_x: titleX,
    content_x: contentX,
    tags_x: tagsX,

    title_facebook: titleFacebook,
    content_facebook: contentFacebook,
    tags_facebook: tagsFacebook,

    title_instagram: titleInstagram,
    content_instagram: contentInstagram,
    tags_instagram: tagsInstagram,

    category_current: row.category_current,

    image_current: row.image_current,
    image_current_id: row.image_current_id,
    featured_media_id: row.featured_media_id,
    featured_media: row.featured_media_id,

    text_versions: JSON.stringify(currentVersions),
    image_versions: row.image_versions,

    keyword_current: keyword,
    image_prompt_current: imagePrompt,

    idioma: row.idioma,
    tamano: row.tamano,
    descripcion: row.descripcion,
    custom_category: row.custom_category,

    publication_type: row.publication_type,
    formato_texto: row.formato_texto,
    tono: row.tono,
    objetivo: row.objetivo,
    publico_objetivo: row.publico_objetivo,
    nivel_tecnico: row.nivel_tecnico,

    cta: row.cta,
    custom_cta: row.custom_cta,
    cta_intensity: row.cta_intensity,

    visual_style: row.visual_style,
    image_format: row.image_format,
    visual_reference: row.visual_reference,

    storytelling_format: row.storytelling_format,
    viral_format: row.viral_format,
    professional_linkedin_format: row.professional_linkedin_format,
    generate_image: row.generate_image,

    review_action: "none",
    status: "reviewed",
    updated_at: new Date().toISOString(),
  },
};

const data = $json;

const {
  tags_current,
  tags,
  tagIds,
  tags_current_ids,
  categories,
  categoryIds,
  ...safeData
} = data;

return {
  json: safeData
};
